import React, { useState, useEffect } from "react";
import { useNavigate, useLocation } from "react-router-dom";

/* ══════════════════════════════════════════════════
   Nev.jsx — Petology Navbar
   • Dark amber theme (matches PetGallery)
   • Mobile hamburger menu
   • Auto-reads login state from localStorage
   • NO external dependencies except react-router-dom
══════════════════════════════════════════════════ */

const CSS = `
@import url('https://fonts.googleapis.com/css2?family=Playfair+Display:ital,wght@0,700;1,700&family=DM+Sans:wght@400;500;600;700&display=swap');

.nv-root {
  position: sticky;
  top: 0;
  z-index: 9000;
  background: rgba(13, 8, 0, 0.92);
  backdrop-filter: blur(16px);
  -webkit-backdrop-filter: blur(16px);
  border-bottom: 1px solid rgba(200, 134, 26, 0.18);
  font-family: 'DM Sans', sans-serif;
}

.nv-inner {
  max-width: 1140px;
  margin: 0 auto;
  padding: 0 24px;
  height: 64px;
  display: flex;
  align-items: center;
  justify-content: space-between;
  gap: 16px;
}

/* ── LOGO ── */
.nv-logo {
  font-family: 'Playfair Display', serif;
  font-size: 1.35rem;
  font-weight: 700;
  color: #e8a840;
  cursor: pointer;
  letter-spacing: 0.02em;
  white-space: nowrap;
  display: flex;
  align-items: center;
  gap: 8px;
  text-decoration: none;
  background: none;
  border: none;
  transition: opacity 0.2s;
}
.nv-logo:hover { opacity: 0.85; }
.nv-logo-paw { font-size: 1.2rem; }

/* ── DESKTOP LINKS ── */
.nv-links {
  display: flex;
  align-items: center;
  gap: 4px;
  flex: 1;
  justify-content: center;
}
.nv-link {
  padding: 7px 14px;
  border-radius: 50px;
  font-size: 0.875rem;
  font-weight: 500;
  color: rgba(240, 224, 192, 0.7);
  cursor: pointer;
  background: none;
  border: none;
  font-family: 'DM Sans', sans-serif;
  transition: all 0.2s;
  white-space: nowrap;
}
.nv-link:hover {
  color: #e8a840;
  background: rgba(200, 134, 26, 0.1);
}
.nv-link.active {
  color: #e8a840;
  background: rgba(200, 134, 26, 0.12);
  font-weight: 600;
}

/* ── RIGHT SIDE ── */
.nv-right {
  display: flex;
  align-items: center;
  gap: 10px;
  flex-shrink: 0;
}

/* Cart button */
.nv-cart {
  position: relative;
  padding: 7px 16px;
  border-radius: 50px;
  background: rgba(200, 134, 26, 0.12);
  border: 1.5px solid rgba(200, 134, 26, 0.3);
  color: #e8a840;
  font-family: 'DM Sans', sans-serif;
  font-size: 0.82rem;
  font-weight: 600;
  cursor: pointer;
  transition: all 0.2s;
  display: flex;
  align-items: center;
  gap: 6px;
  white-space: nowrap;
}
.nv-cart:hover {
  background: rgba(200, 134, 26, 0.22);
  border-color: #c8861a;
  transform: translateY(-1px);
}

/* Login / Logout button */
.nv-login-btn {
  padding: 8px 20px;
  border-radius: 50px;
  background: #c8861a;
  border: none;
  color: #fff;
  font-family: 'DM Sans', sans-serif;
  font-size: 0.82rem;
  font-weight: 700;
  cursor: pointer;
  transition: all 0.2s;
  white-space: nowrap;
  box-shadow: 0 4px 14px rgba(200, 134, 26, 0.35);
}
.nv-login-btn:hover {
  background: #a06010;
  transform: translateY(-1px);
  box-shadow: 0 6px 20px rgba(200, 134, 26, 0.45);
}

/* User greeting */
.nv-user {
  font-size: 0.8rem;
  color: rgba(240, 224, 192, 0.55);
  white-space: nowrap;
  max-width: 120px;
  overflow: hidden;
  text-overflow: ellipsis;
}

/* ── HAMBURGER (mobile) ── */
.nv-burger {
  display: none;
  flex-direction: column;
  gap: 5px;
  cursor: pointer;
  padding: 6px;
  background: none;
  border: none;
}
.nv-burger span {
  display: block;
  width: 22px;
  height: 2px;
  background: #e8a840;
  border-radius: 2px;
  transition: all 0.3s;
}
.nv-burger.open span:nth-child(1) { transform: rotate(45deg) translate(5px, 5px); }
.nv-burger.open span:nth-child(2) { opacity: 0; }
.nv-burger.open span:nth-child(3) { transform: rotate(-45deg) translate(5px, -5px); }

/* ── MOBILE DRAWER ── */
.nv-drawer {
  display: none;
  flex-direction: column;
  background: rgba(13, 8, 0, 0.98);
  border-top: 1px solid rgba(200, 134, 26, 0.15);
  padding: 16px 24px 24px;
  gap: 6px;
  animation: nvSlideDown 0.25s ease;
}
@keyframes nvSlideDown {
  from { opacity: 0; transform: translateY(-8px); }
  to   { opacity: 1; transform: translateY(0); }
}
.nv-drawer.open { display: flex; }
.nv-drawer .nv-link {
  width: 100%;
  text-align: left;
  border-radius: 12px;
  padding: 11px 16px;
  font-size: 0.95rem;
}
.nv-drawer-divider {
  height: 1px;
  background: rgba(200, 134, 26, 0.12);
  margin: 8px 0;
}
.nv-drawer .nv-login-btn,
.nv-drawer .nv-cart {
  width: 100%;
  justify-content: center;
  border-radius: 12px;
  padding: 12px;
  font-size: 0.9rem;
}

/* ── RESPONSIVE ── */
@media (max-width: 768px) {
  .nv-links  { display: none; }
  .nv-user   { display: none; }
  .nv-cart   { display: none; }
  .nv-login-btn { display: none; }
  .nv-burger { display: flex; }
}
`;

/* ── Nav links config ── */
const LINKS = [
  { label: "Home",     path: "/"         },
  { label: "Pets",     path: "/product"  },
  { label: "Cart",     path: "/cart"     },
  { label: "My Orders",path: "/myorder"  },
  { label: "Contact",  path: "/contact"  },
];

export default function Nev() {
  const navigate  = useNavigate();
  const location  = useLocation();

  const [isLoggedIn, setIsLoggedIn] = useState(false);
  const [userName,   setUserName]   = useState("");
  const [menuOpen,   setMenuOpen]   = useState(false);

  /* Read login state on every route change */
  useEffect(() => {
    const logged = localStorage.getItem("islogin");
    const name   = localStorage.getItem("uname") || "";
    setIsLoggedIn(!!logged);
    setUserName(name);
  }, [location.pathname]);

  /* Close mobile menu on route change */
  useEffect(() => { setMenuOpen(false); }, [location.pathname]);

  const go = (path) => {
    navigate(path);
    setMenuOpen(false);
  };

  const handleLogout = () => {
    localStorage.removeItem("islogin");
    localStorage.removeItem("uname");
    localStorage.removeItem("email");
    localStorage.removeItem("id");
    localStorage.removeItem("item");
    localStorage.removeItem("pid");
    setIsLoggedIn(false);
    setUserName("");
    navigate("/login");
    setMenuOpen(false);
  };

  const isActive = (path) => location.pathname === path;

  return (
    <>
      <style dangerouslySetInnerHTML={{ __html: CSS }} />

      <nav className="nv-root">
        <div className="nv-inner">

          {/* Logo */}
          <button className="nv-logo" onClick={() => go("/")}>
            <span className="nv-logo-paw">🐾</span>
            Petology
          </button>

          {/* Desktop links */}
          <div className="nv-links">
            {LINKS.map((l) => (
              <button
                key={l.path}
                className={"nv-link" + (isActive(l.path) ? " active" : "")}
                onClick={() => go(l.path)}
              >
                {l.label}
              </button>
            ))}
          </div>

          {/* Desktop right */}
          <div className="nv-right">
            {isLoggedIn && (
              <>
                <span className="nv-user">Hi, {userName || "User"} 👋</span>
                <button className="nv-cart" onClick={() => go("/cart")}>
                  🛒 Cart
                </button>
                <button className="nv-login-btn" onClick={handleLogout}>
                  Logout
                </button>
              </>
            )}
            {!isLoggedIn && (
              <button className="nv-login-btn" onClick={() => go("/login")}>
                Login / Signup
              </button>
            )}
          </div>

          {/* Hamburger */}
          <button
            className={"nv-burger" + (menuOpen ? " open" : "")}
            onClick={() => setMenuOpen((o) => !o)}
            aria-label="Toggle menu"
          >
            <span /><span /><span />
          </button>
        </div>

        {/* Mobile drawer */}
        <div className={"nv-drawer" + (menuOpen ? " open" : "")}>
          {LINKS.map((l) => (
            <button
              key={l.path}
              className={"nv-link" + (isActive(l.path) ? " active" : "")}
              onClick={() => go(l.path)}
            >
              {l.label}
            </button>
          ))}
          <div className="nv-drawer-divider" />
          {isLoggedIn ? (
            <>
              <div style={{ fontSize: "0.82rem", color: "rgba(240,224,192,0.5)", padding: "4px 16px" }}>
                Logged in as <strong style={{ color: "#e8a840" }}>{userName}</strong>
              </div>
              <button className="nv-login-btn" onClick={handleLogout}>
                Logout
              </button>
            </>
          ) : (
            <button className="nv-login-btn" onClick={() => go("/login")}>
              Login / Signup
            </button>
          )}
        </div>
      </nav>
    </>
  );
}
